arguments.prompt:
You are implementing features for a Blazor Web App shipment tracker at /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker. The project uses Interactive Auto Global mode with Individual authentication. It has two projects: ShipmentTracker (server) and ShipmentTracker.Client (WebAssembly).

The app needs:
1. A Shipment model and data
2. A shared service interface in the Client project
3. Server implementation using EF Core, client implementation using HttpClient
4. API endpoints on the server
5. Dispatcher page: shows list of all shipments with status, destination, and ability to update status
6. Customer page: lets customers enter a tracking number to check status and estimated delivery
7. Role-based authorization: Dispatchers see the dispatcher page, customers see the tracking page

Here's what already exists:
- Server Program.cs has Identity, EF Core with SQLite, and all the Auto mode wiring
- Client Program.cs has auth deserialization set up
- The ApplicationDbContext is at ShipmentTracker.Data.ApplicationDbContext
- The ApplicationUser is at ShipmentTracker.Data.ApplicationUser

Please do the following:

### 1. Create the Shipment model in the Server project

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker/Data/Shipment.cs

```csharp
namespace ShipmentTracker.Data;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Exception
}
```

### 2. Create the shared DTO and interface in the Client project

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker.Client/Services/ShipmentDto.cs

```csharp
namespace ShipmentTracker.Client.Services;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public DateTime CreatedDate { get; set; }
    public DateTime EstimatedDelivery { get; set; }
    public string CustomerEmail { get; set; } = string.Empty;
}
```

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker.Client/Services/IShipmentService.cs

```csharp
namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetAllShipmentsAsync();
    Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task UpdateShipmentStatusAsync(int id, string status);
}
```

### 3. Create the Client-side implementation (HttpClient)

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker.Client/Services/ShipmentServiceClient.cs

```csharp
using System.Net.Http.Json;

namespace ShipmentTracker.Client.Services;

public class ShipmentServiceClient(HttpClient httpClient) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await httpClient.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? [];
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await httpClient.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }

    public async Task UpdateShipmentStatusAsync(int id, string status)
    {
        await httpClient.PutAsJsonAsync($"api/shipments/{id}/status", new { Status = status });
    }
}
```

### 4. Create the Server-side implementation (EF Core)

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker/Services/ShipmentServiceServer.cs

```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServiceServer(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetAllShipmentsAsync()
    {
        return await db.Shipments.Select(s => new ShipmentDto
        {
            Id = s.Id,
            TrackingNumber = s.TrackingNumber,
            Origin = s.Origin,
            Destination = s.Destination,
            Status = s.Status.ToString(),
            CreatedDate = s.CreatedDate,
            EstimatedDelivery = s.EstimatedDelivery,
            CustomerEmail = s.CustomerEmail
        }).ToListAsync();
    }

    public async Task<ShipmentDto?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        if (shipment is null) return null;
        return new ShipmentDto
        {
            Id = shipment.Id,
            TrackingNumber = shipment.TrackingNumber,
            Origin = shipment.Origin,
            Destination = shipment.Destination,
            Status = shipment.Status.ToString(),
            CreatedDate = shipment.CreatedDate,
            EstimatedDelivery = shipment.EstimatedDelivery,
            CustomerEmail = shipment.CustomerEmail
        };
    }

    public async Task UpdateShipmentStatusAsync(int id, string status)
    {
        var shipment = await db.Shipments.FindAsync(id);
        if (shipment is not null && Enum.TryParse<ShipmentStatus>(status, out var parsedStatus))
        {
            shipment.Status = parsedStatus;
            await db.SaveChangesAsync();
        }
    }
}
```

### 5. Update ApplicationDbContext to include Shipments DbSet

Read the existing file at /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker/Data/ApplicationDbContext.cs and add:
```csharp
public DbSet<Shipment> Shipments => Set<Shipment>();
```

### 6. Create API endpoints file

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker/ShipmentEndpoints.cs

```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("", async (ApplicationDbContext db) =>
        {
            return await db.Shipments.Select(s => new ShipmentDto
            {
                Id = s.Id,
                TrackingNumber = s.TrackingNumber,
                Origin = s.Origin,
                Destination = s.Destination,
                Status = s.Status.ToString(),
                CreatedDate = s.CreatedDate,
                EstimatedDelivery = s.EstimatedDelivery,
                CustomerEmail = s.CustomerEmail
            }).ToListAsync();
        }).RequireAuthorization("Dispatcher");

        group.MapGet("track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
            if (shipment is null) return Results.NotFound();
            return Results.Ok(new ShipmentDto
            {
                Id = shipment.Id,
                TrackingNumber = shipment.TrackingNumber,
                Origin = shipment.Origin,
                Destination = shipment.Destination,
                Status = shipment.Status.ToString(),
                CreatedDate = shipment.CreatedDate,
                EstimatedDelivery = shipment.EstimatedDelivery,
                CustomerEmail = shipment.CustomerEmail
            });
        }).RequireAuthorization();

        group.MapPut("{id}/status", async (int id, StatusUpdateRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null) return Results.NotFound();
            if (!Enum.TryParse<ShipmentStatus>(request.Status, out var status)) return Results.BadRequest("Invalid status");
            shipment.Status = status;
            await db.SaveChangesAsync();
            return Results.Ok();
        }).RequireAuthorization("Dispatcher");
    }
}

public record StatusUpdateRequest(string Status);
```

### 7. Update Server Program.cs

In /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker/Program.cs, add after the Identity services registration (after `builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();`):

```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServiceServer>();
builder.Services.AddAuthorization(options =>
{
    options.AddPolicy("Dispatcher", policy => policy.RequireRole("Dispatcher"));
});
```

Also add the necessary usings at the top:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
```

And before `app.Run();`, add:
```csharp
app.MapShipmentEndpoints();
```

### 8. Update Client Program.cs

In /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker.Client/Program.cs, add the HttpClient and service registrations:

```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore(options =>
{
    options.AddPolicy("Dispatcher", policy => policy.RequireRole("Dispatcher"));
});
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddScoped(sp => new HttpClient { BaseAddress = new Uri(builder.HostEnvironment.BaseAddress) });
builder.Services.AddScoped<IShipmentService, ShipmentServiceClient>();

await builder.Build().RunAsync();
```

### 9. Create the Dispatcher page in the Client project

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker.Client/Pages/Dispatch.razor

```razor
@page "/dispatch"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Services
@attribute [Authorize(Policy = "Dispatcher")]
@inject IShipmentService ShipmentService

<PageTitle>Dispatch Dashboard</PageTitle>

<h1>Shipment Dispatch</h1>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <p>No shipments found.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in shipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                    </td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width: auto; display: inline-block;"
                                value="@shipment.Status"
                                @onchange="(e) => UpdateStatus(shipment, e.Value?.ToString())">
                            <option value="Pending">Pending</option>
                            <option value="PickedUp">Picked Up</option>
                            <option value="InTransit">In Transit</option>
                            <option value="OutForDelivery">Out for Delivery</option>
                            <option value="Delivered">Delivered</option>
                            <option value="Exception">Exception</option>
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<ShipmentDto>? shipments;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private async Task UpdateStatus(ShipmentDto shipment, string? newStatus)
    {
        if (newStatus is null || newStatus == shipment.Status) return;
        await ShipmentService.UpdateShipmentStatusAsync(shipment.Id, newStatus);
        shipment.Status = newStatus;
    }

    private static string GetStatusBadgeClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "PickedUp" => "bg-info",
        "InTransit" => "bg-primary",
        "OutForDelivery" => "bg-warning text-dark",
        "Delivered" => "bg-success",
        "Exception" => "bg-danger",
        _ => "bg-secondary"
    };
}
```

### 10. Create the Customer tracking page in the Client project

Create file: /tmp/sv-38da10e02cd941b59312973f90060fea/ShipmentTracker/ShipmentTracker.Client/Pages/Track.razor

```razor
@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Services
