using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;

namespace ShipmentTracker.Data;

public static class SeedData
{
    public static async Task InitializeAsync(IServiceProvider serviceProvider)
    {
        using var scope = serviceProvider.CreateScope();
        var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
        await db.Database.MigrateAsync();

        if (await db.Shipments.AnyAsync()) return;

        db.Shipments.AddRange(
            new Shipment
            {
                TrackingNumber = "TRK-001234",
                Origin = "New York, NY",
                Destination = "Los Angeles, CA",
                Status = ShipmentStatus.InTransit,
                CreatedDate = DateTime.UtcNow.AddDays(-3),
                EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                CustomerEmail = "customer@example.com"
            },
            new Shipment
            {
                TrackingNumber = "TRK-005678",
                Origin = "Chicago, IL",
                Destination = "Miami, FL",
                Status = ShipmentStatus.PickedUp,
                CreatedDate = DateTime.UtcNow.AddDays(-1),
                EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                CustomerEmail = "customer@example.com"
            },
            new Shipment
            {
                TrackingNumber = "TRK-009012",
                Origin = "Seattle, WA",
                Destination = "Denver, CO",
                Status = ShipmentStatus.OutForDelivery,
                CreatedDate = DateTime.UtcNow.AddDays(-5),
                EstimatedDelivery = DateTime.UtcNow,
                CustomerEmail = "another@example.com"
            },
            new Shipment
            {
                TrackingNumber = "TRK-003456",
